-- Reconstruct Country from local_1.countryReference
CREATE VIEW "Country" AS
SELECT
    "local_1"."countryReference"."countryId" AS "id",
    "local_1"."countryReference"."countryName" AS "name"
FROM "local_1"."countryReference";

-- Reconstruct League from local_2.CompetitionLeague
CREATE VIEW "League" AS
SELECT
    "local_2"."CompetitionLeague"."LeagueId" AS "id",
    "local_2"."CompetitionLeague"."CountryId" AS "country_id",
    "local_2"."CompetitionLeague"."LeagueName" AS "name"
FROM "local_2"."CompetitionLeague";

