-- Reconstruct Team from local_3.tm_core
CREATE VIEW "Team" AS
SELECT
    "local_3"."tm_core"."rec_id" AS "id",
    "local_3"."tm_core"."team_ext_id" AS "team_api_id",
    "local_3"."tm_core"."team_fifa_id" AS "team_fifa_api_id",
    "local_3"."tm_core"."team_name_long" AS "team_long_name",
    "local_3"."tm_core"."team_name_short" AS "team_short_name"
FROM "local_3"."tm_core";

-- Reconstruct Team_Attributes from vertical split + row partition on a fragment
CREATE VIEW "Team_Attributes" AS
SELECT t0.[TeamAttributeId], t4.[team_fifa_id], t4.[team_ext_id], t2.[attr_date], t0.[BuildUpPlaySpeedValue], t0.[BuildUpPlaySpeedCategory], t0.[BuildUpPlayDribblingValue], t0.[BuildUpPlayDribblingCategory], t0.[BuildUpPlayPassingValue], t0.[BuildUpPlayPassingCategory], t0.[BuildUpPlayPositioningCategory], t0.[ChanceCreationPassingValue], t0.[ChanceCreationPassingCategory], t1.[ChanceCreationCrossingValue], t1.[ChanceCreationCrossingCategory], t1.[ChanceCreationShootingValue], t1.[ChanceCreationShootingCategory], t0.[ChanceCreationPositioningCategory], t3.[def_press], t3.[def_press_class], t2.[def_aggr], t2.[def_aggr_class], t2.[def_team_width], t3.[def_team_width_class], t2.[def_line_class]
